static createCookie(nome,valor,tempo,opcao='dias'){var expires;if(tempo){var date=new Date();if(opcao=='dias'){date.setTime(date.getTime()+(tempo*24*60*60*1000))}else if(opcao=='horas'){date.setTime(date.getTime()+(tempo*60*60*1000))}else if(opcao=='minutos'){date.setTime(date.getTime()+(tempo*60*1000))}
expires="; expires="+date.toGMTString()}else{expires=""}
document.cookie=nome+"="+valor+expires+"; path=/"}
static getCookie(c_name){if(document.cookie.length>0){var c_start=document.cookie.indexOf(c_name+"=");if(c_start!=-1){c_start=c_start+c_name.length+1;var c_end=document.cookie.indexOf(";",c_start);if(c_end==-1){c_end=document.cookie.length}
return unescape(document.cookie.substring(c_start,c_end))}}
return""}
